+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track = {min: number; fr: number; auto: boolean};
+
+const tracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {min: 0, fr: 0, auto: true};
+		const minmax = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?fr|\\d+(?:\\.\\d+)?)\\s*\\)$/.exec(token);
+		if (minmax) return {min: Number(minmax[1]), fr: minmax[2].endsWith('fr') ? Number.parseFloat(minmax[2]) : 0, auto: false};
+		if (token.endsWith('fr')) return {min: 0, fr: Number.parseFloat(token), auto: false};
+		return {min: Number(token), fr: 0, auto: false};
+	});
+};
+
+const range = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value - 1, value];
+	if (!value) return undefined;
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	return match ? [Number(match[1]) - 1, Number(match[2]) - 1] : undefined;
+};
+
+const resolve = (list: Track[], available: number, gap: number, autoSizes: number[]): number[] => {
+	const sizes = list.map((track, index) => track.auto ? Math.max(track.min, autoSizes[index] ?? 0) : track.min);
+	const remaining = Math.max(0, available - sizes.reduce((a, b) => a + b, 0) - Math.max(0, list.length - 1) * gap);
+	const totalFr = list.reduce((sum, track) => sum + track.fr, 0);
+	if (totalFr) for (let index = 0; index < list.length; index++) sizes[index] += remaining * list[index].fr / totalFr;
+	return sizes;
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const yoga = node.yogaNode;
+	if (!yoga || node.style.display !== 'grid') return;
+	const children = node.childNodes.filter((child): child is DOMElement => Boolean(child.yogaNode));
+	let columns = tracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{min: 0, fr: 1, auto: false}];
+	let rows = tracks(node.style.gridTemplateRows);
+	const placements: Array<{child: DOMElement; column: [number, number]; row: [number, number]}> = [];
+	let cursor = 0;
+	for (const child of children) {
+		const column = range(child.style.gridColumn);
+		const row = range(child.style.gridRow);
+		const start = cursor++;
+		placements.push({child, column: column ?? [start % columns.length, start % columns.length + 1], row: row ?? [Math.floor(start / columns.length), Math.floor(start / columns.length) + 1]});
+	}
+	const rowCount = Math.max(rows.length, ...placements.map(item => item.row[1]), 0);
+	while (rows.length < rowCount) rows.push({min: 0, fr: 0, auto: true});
+	const columnAuto = columns.map(() => 0);
+	const rowAuto = rows.map(() => 0);
+	for (const {child, column, row} of placements) {
+		if (column[1] - column[0] === 1) columnAuto[column[0]] = Math.max(columnAuto[column[0]], child.yogaNode!.getComputedWidth());
+		if (row[1] - row[0] === 1) rowAuto[row[0]] = Math.max(rowAuto[row[0]], child.yogaNode!.getComputedHeight());
+	}
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const width = yoga.getComputedWidth() - yoga.getComputedPadding(Yoga.EDGE_LEFT) - yoga.getComputedPadding(Yoga.EDGE_RIGHT);
+	const height = yoga.getComputedHeight() - yoga.getComputedPadding(Yoga.EDGE_TOP) - yoga.getComputedPadding(Yoga.EDGE_BOTTOM);
+	const columnSizes = resolve(columns, width, columnGap, columnAuto);
+	const rowSizes = resolve(rows, height, rowGap, rowAuto);
+	if (node.style.height === undefined) yoga.setHeight(rowSizes.reduce((a, b) => a + b, 0) + Math.max(0, rows.length - 1) * rowGap + yoga.getComputedPadding(Yoga.EDGE_TOP) + yoga.getComputedPadding(Yoga.EDGE_BOTTOM));
+	for (const {child, column, row} of placements) {
+		const childYoga = child.yogaNode!;
+		const left = columnSizes.slice(0, column[0]).reduce((a, b) => a + b, 0) + column[0] * columnGap;
+		const top = rowSizes.slice(0, row[0]).reduce((a, b) => a + b, 0) + row[0] * rowGap;
+		const childWidth = columnSizes.slice(column[0], column[1]).reduce((a, b) => a + b, 0) + Math.max(0, column[1] - column[0] - 1) * columnGap;
+		const childHeight = rowSizes.slice(row[0], row[1]).reduce((a, b) => a + b, 0) + Math.max(0, row[1] - row[0] - 1) * rowGap;
+		childYoga.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		childYoga.setPosition(Yoga.EDGE_LEFT, left);
+		childYoga.setPosition(Yoga.EDGE_TOP, top);
+		childYoga.setWidth(childWidth);
+		childYoga.setHeight(childHeight);
+	}
+};
+
+export const applyGridLayout = (node: DOMElement): void => {
+	layoutGrid(node);
+	for (const child of node.childNodes) if (child.nodeName !== '#text') applyGridLayout(child);
+};
